def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 20):
            if j % 4 == 0:
                factor = 1.3
            elif j % 5 == 0:
                factor = 1.15
            elif j % 2 == 0:
                factor = 1.05
            else:
                factor = 0.85
            term = factor * np.exp(-j/10) * (ratio ** (j + 0.5))
            score += term
            if term < 1e-5:
                break
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
            if item > 0.8 * capacity:
                score *= 1.3
        elif remaining < 0.08 * capacity:
            score *= 1.8
        elif remaining < 0.15 * capacity:
            score *= 1.2
        elif remaining < 0.3 * capacity:
            score *= 0.9
        else:
            score *= 0.6
        mods = {3: int(capacity) % 3 == 0,
                5: int(capacity) % 5 == 0,
                7: int(capacity) % 7 == 0,
                11: int(capacity) % 11 == 0 }
        if mods[3] and mods[5] and mods[7]:
            score -= 0.15 * (capacity / 7)
        elif mods[3] and mods[5]:
            score -= 0.13 * (capacity / 9)
        elif mods[5] and mods[7]:
            score -= 0.2 * (capacity / 14)
        elif mods[3] and mods[7]:
            score -= 0.11 * (capacity / 18)
        elif mods[11]:
            score -= 0.25 * (capacity / 25)
        elif mods[5]:
            score -= 0.12 * (capacity / 22)
        elif mods[3]:
            score -= 0.06 * (capacity / 15)
        elif mods[7]:
            score -= 0.08 * (capacity / 19)
        else:
            score -= 0.04 * (capacity / 28)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.8 * threshold:
                penalty += 0.12 * k
            elif diff < 3 * threshold:
                penalty -= 0.06 * k
            else:
                penalty -= 0.08 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 5):
                val = capacity / (m + 0.5)
                if abs(val - item) < 0.025 * val:
                    score *= (1 + 0.07 * m)
        frac_cap = capacity - int(capacity)
        if 0.1 < frac_cap < 0.3:
            score *= 0.95
        elif 0.7 < frac_cap < 0.95:
            score *= 1.05
        if int(capacity) % 2 == 0:
            if remaining < 0.05 * capacity:
                score += 0.4
            else:
                score -= 0.15
        else:
            if ratio > 0.75 and remaining > 0.1 * capacity:
                score += 0.6
            else:
                score -= 0.1
        priorities[i] = score
    return priorities
